        private static X509Certificate2 LoadOrCreateDemoCertificate(string path, string password, string subjectName)
        {
            if (!string.IsNullOrEmpty(path) && System.IO.File.Exists(path))
            {
                return new X509Certificate2(path, password, X509KeyStorageFlags.Exportable);
            }

            // Generate a self-signed certificate for demonstration
            using RSA rsa = RSA.Create(2048);
            var request = new CertificateRequest(
                subjectName,
                rsa,
                HashAlgorithmName.SHA256,
                RSASignaturePadding.Pkcs1);

            request.CertificateExtensions.Add(
                new X509KeyUsageExtension(
                    X509KeyUsageFlags.DigitalSignature | X509KeyUsageFlags.KeyEncipherment,
                    critical: true));

            var cert = request.CreateSelfSigned(
                DateTimeOffset.UtcNow.AddMinutes(-5),
                DateTimeOffset.UtcNow.AddYears(2));

            // On Windows, re-export to make the private key available
            return new X509Certificate2(
                cert.Export(X509ContentType.Pfx, "temp"),
                "temp",
                X509KeyStorageFlags.Exportable);
        }

